# 1. Any iterable works in a for loop
class Fibonacci:
    def __init__(self, n):
        self.n = n
    def __iter__(self):
        a, b, count = 0, 1, 0
        while count < self.n:
            yield a
            a, b = b, a + b
            count += 1

for num in Fibonacci(5):  # Works because it has __iter__
    print(num)

