# Merge with custom conflict resolution
def merge_with(d1, d2, resolver):
    """Merge dicts using a resolver function for conflicts."""
    result = d1.copy()
    for key, value in d2.items():
        if key in result:
            result[key] = resolver(result[key], value)
        else:
            result[key] = value
    return result

# Sum values for duplicate keys
scores1 = {'alice': 10, 'bob': 20}
scores2 = {'bob': 15, 'charlie': 25}
merged = merge_with(scores1, scores2, lambda a, b: a + b)
print(merged)  # {'alice': 10, 'bob': 35, 'charlie': 25}

